-- 3. VERIFY
SELECT
  key,
  jsonb_array_length(value) AS records,
  updated_at
FROM kv_store
WHERE key IN ('payrollExtra', 'timesheet');

SELECT
  '✅ Đã seed ' || jsonb_array_length(value) || ' phiếu lương T4/2026 (status=submitted)' AS done
FROM kv_store
WHERE key = 'payrollExtra';
